      { name: "Chicken Teriyaki Futomaki", price: "₹599" },
      { name: "Smoked Salmon Maki", price: "₹699" },
    ]
  },
  {
    id: "fries-nachos",
    name: "Fries & Nachos",
    icon: Flame,
    items: [
      { name: "Peri Peri Fries", price: "₹249" },
      { name: "Truffle French Fry", price: "₹399" },
      { name: "Loaded Nachos", price: "₹549 / 599" },
    ]
  },
  {
    id: "oriental-starters",
    name: "Oriental Starters",
    icon: Flame,
    items: [
      { name: "Golden Fried Baby Corn", price: "₹199" },
      { name: "Corn Salt & Pepper", price: "₹249" },
      { name: "Crackling Spinach", price: "₹249" },
      { name: "Crispy Chilli Baby Corn", price: "₹299" },
      { name: "Chilli Lotus Stem", price: "₹299" },
      { name: "Sesame Paneer Sticks", price: "₹299" },
      { name: "Crispy Konjee Vegetable", price: "₹349" },
      { name: "Schezwan Paneer Dry", price: "₹399" },
      { name: "Soya Chilli Mushroom", price: "₹449" },
      { name: "Drums of Heaven", price: "₹349" },
      { name: "Honey Chilli Chicken", price: "₹349" },
      { name: "Cilantro Chilli Chicken", price: "₹349" },
      { name: "Chicken Wings", price: "₹349" },
      { name: "Tangra Style Chilli Chicken", price: "₹399" },
      { name: "Chicken Yakitori", price: "₹449" },
      { name: "Steamed Fish", price: "₹449" },
      { name: "Kung Pao Chicken", price: "₹499" },
      { name: "Golden Fried Prawn", price: "₹499" },
      { name: "Butter Chilli Garlic Prawns", price: "₹499" },
      { name: "Pan Fried Chilli Fish", price: "₹599" },
      { name: "Honey Soya Pork Belly", price: "₹599" },
    ]
  },
  {
    id: "starters",
    name: "Starters",
    icon: Flame,
    items: [
      { name: "Crispy Calamari", description: "Golden fried squid rings with garlic aioli", price: "₹495" },
      { name: "Chicken Wings", description: "Buffalo style with blue cheese dip", price: "₹445" },
      { name: "Loaded Nachos", description: "Cheese, jalapeños, salsa, sour cream", price: "₹395" },
      { name: "Paneer Tikka", description: "Tandoori spiced cottage cheese skewers", price: "₹375" },
      { name: "Fish Fingers", description: "Beer battered with tartar sauce", price: "₹475" },
      { name: "Mushroom Bruschetta", description: "Garlic toast with sautéed mushrooms", price: "₹325" },
    ]
  },
  {
    id: "mains",
    name: "Main Course",
    icon: UtensilsCrossed,
    items: [
      { name: "Grilled Chicken Steak", description: "With herb butter and mashed potatoes", price: "₹695" },
      { name: "Fish & Chips", description: "Beer battered fish with crispy fries", price: "₹595" },
      { name: "Butter Chicken", description: "Creamy tomato gravy with naan", price: "₹545" },
      { name: "Lamb Chops", description: "Rosemary grilled with mint chutney", price: "₹895" },
      { name: "Penne Arrabiata", description: "Spicy tomato sauce with parmesan", price: "₹445" },
      { name: "Thai Green Curry", description: "Vegetables in coconut curry with rice", price: "₹475" },
    ]
  },
  {
    id: "pizza",
    name: "Pizza",
    icon: UtensilsCrossed,
    items: [
      { name: "Margherita", description: "Fresh tomato, mozzarella, basil", price: "₹395" },
      { name: "Pepperoni", description: "Spicy pepperoni with cheese", price: "₹495" },
      { name: "BBQ Chicken", description: "Grilled chicken, onions, BBQ sauce", price: "₹545" },
      { name: "Mushroom & Truffle", description: "Wild mushrooms with truffle oil", price: "₹595" },
      { name: "Four Cheese", description: "Mozzarella, cheddar, parmesan, blue cheese", price: "₹545" },
    ]
  },
  {
    id: "cocktails",
    name: "Signature Cocktails",
    icon: Martini,
    items: [
      { name: "Corridor Special", description: "Our secret blend - vodka, passion fruit, lime", price: "₹595" },
      { name: "Kolkata Sunset", description: "Rum, orange, grenadine, pineapple", price: "₹545" },
      { name: "Smoky Old Fashioned", description: "Bourbon, bitters, smoked rosemary", price: "₹645" },
      { name: "Espresso Martini", description: "Vodka, coffee liqueur, fresh espresso", price: "₹575" },
      { name: "Passion Mojito", description: "White rum, passion fruit, mint, lime", price: "₹495" },
      { name: "Mango Margarita", description: "Tequila, triple sec, fresh mango", price: "₹545" },
    ]
  },
  {
    id: "whiskey",
    name: "Whiskey & Spirits",
    icon: Wine,
    items: [
      { name: "Johnnie Walker Black", description: "12 Year Old Blended Scotch", price: "₹445/peg" },
      { name: "Jack Daniel's", description: "Tennessee Whiskey", price: "₹395/peg" },
      { name: "Glenfiddich 12", description: "Single Malt Scotch", price: "₹595/peg" },
      { name: "Chivas Regal 18", description: "Blended Scotch", price: "₹695/peg" },
      { name: "Monkey Shoulder", description: "Triple Malt Scotch", price: "₹495/peg" },
      { name: "Absolut Vodka", description: "Swedish Premium Vodka", price: "₹345/peg" },
    ]
  },
  {
    id: "beer",
    name: "Beer & More",
    icon: Beer,
    items: [
      { name: "Kingfisher Premium", description: "Indian Lager", price: "₹295" },
      { name: "Corona Extra", description: "Mexican Lager with lime", price: "₹445" },
      { name: "Budweiser", description: "American Lager", price: "₹345" },
      { name: "Hoegaarden", description: "Belgian Wheat Beer", price: "₹495" },
      { name: "Bira White", description: "Indian Craft Wheat", price: "₹295" },
      { name: "Guinness Draught", description: "Irish Stout", price: "₹545" },
    ]
  },
  {
    id: "desserts",
    name: "Desserts",
    icon: IceCream,
    items: [
      { name: "Chocolate Lava Cake", description: "Warm center with vanilla ice cream", price: "₹345" },
      { name: "Tiramisu", description: "Classic Italian coffee dessert", price: "₹325" },
      { name: "New York Cheesecake", description: "With berry compote", price: "₹295" },
      { name: "Brownie Sundae", description: "Warm brownie with ice cream & fudge", price: "₹325" },
    ]
  }
];

// Food images for visual appeal - UNDO to ORIGINAL + beer.jpg only change
const categoryImages = {
  salad: "/assets/menu_images/salad.jpg",
  sushi: "/assets/menu_images/sushi.jpg",
  "fries-nachos": "/assets/menu_images/fries_nachos.jpg",
  "oriental-starters": "/assets/menu_images/oriental_starters.jpg",
  starters: "/assets/menu_images/starters.jpg", // make sure this file exists
  mains: "/assets/menu_images/main_course.jpg", // or main_couse.jpg if that's your file
  pizza: "/assets/menu_images/pizza.jpg",
  cocktails: "/assets/menu_images/cocktails.jpg",
  whiskey: "/assets/menu_images/whiskey.jpg",
  beer: "/assets/menu_images/beer.jpg",
  desserts: "/assets/menu_images/dessert.jpg",
};
const MenuPage = () => {
const [activeCategory, setActiveCategory] = useState("salad");

  const activeMenuCategory = menuCategories.find(cat => cat.id === activeCategory);

  return (
    <main data-testid="menu-page" className="bg-black min-h-screen pt-24 md:pt-32">
      {/* Hero */}
      <section className="max-w-[1400px] mx-auto px-6 md:px-12 pb-12">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="text-center"
        >
          <span className="font-accent text-gold text-sm tracking-[0.3em] uppercase">
            Culinary Excellence
          </span>
          <h1 className="font-heading text-5xl md:text-7xl text-white mt-4 mb-6">
            Our Menu
          </h1>
          <p className="font-body text-zinc-400 text-lg max-w-2xl mx-auto">
            From handcrafted cocktails to gourmet cuisine, discover flavors that 
            define the Corridor experience.
          </p>
        </motion.div>
      </section>

      {/* Category Navigation */}
      <section className="max-w-[1400px] mx-auto px-6 md:px-12 pb-8">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.2 }}
          className="flex flex-wrap justify-center gap-3 md:gap-4"
        >
          {menuCategories.map((category) => {
            const IconComponent = category.icon;
            return (
              <button
                key={category.id}
                data-testid={`menu-category-${category.id}`}
                onClick={() => setActiveCategory(category.id)}
                className={`flex items-center gap-2 px-4 md:px-6 py-2.5 font-body text-xs md:text-sm tracking-[0.1em] uppercase transition-all duration-300 border ${
                  activeCategory === category.id
                    ? "bg-gold text-black border-gold"
                    : "bg-transparent text-white border-zinc-700 hover:border-gold hover:text-gold"
                }`}
              >
                <IconComponent size={16} />
                <span className="hidden sm:inline">{category.name}</span>
                <span className="sm:hidden">{category.name.split(' ')[0]}</span>
              </button>
            );
          })}
        </motion.div>
      </section>

      {/* Menu Content */}
      <section className="max-w-[1400px] mx-auto px-6 md:px-12 pb-24">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Category Image */}
          <motion.div
            key={`image-${activeCategory}`}
            initial={{ opacity: 0, x: -30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6 }}
className="lg:col-span-1"
          >
            <div className="relative aspect-[3/4] overflow-hidden border border-zinc-800 sticky top-32 lg:top-24">

  <img
src={categoryImages?.[activeCategory] || "/assets/salad.jpg"}
    alt={activeMenuCategory?.name || "Menu"}
    className="w-full h-full object-cover"
    loading="lazy"
    onError={(e) => {
      console.log("Image failed:", categoryImages?.[activeCategory]);
      e.target.src =
        "https://images.unsplash.com/photo-1546069901-ba9599a7e63c";
    }}
  />

  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />

  <div className="absolute bottom-0 left-0 right-0 p-6">
    <h3 className="font-heading text-3xl text-white">
      {activeMenuCategory?.name}
    </h3>
  </div>

</div>
          </motion.div>

          {/* Menu Items */}
          <motion.div
            key={`items-${activeCategory}`}
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6 }}
            className="lg:col-span-2"
          >
            <div className="space-y-1">
              {activeMenuCategory?.items.map((item, index) => (
                <motion.div
                  key={item.name}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.4, delay: index * 0.05 }}
                  data-testid={`menu-item-${index}`}
                  className="group p-6 border-b border-zinc-800 hover:bg-zinc-900/50 transition-colors duration-300"
                >
                  <div className="flex justify-between items-start gap-4">
                    <div className="flex-1">
                      <h4 className="font-heading text-xl text-white group-hover:text-gold transition-colors">
                        {item.name}
                      </h4>
                      <p className="font-body text-sm text-zinc-500 mt-1">
                        {item.description}
                      </p>
                    </div>
                    <div className="font-heading text-xl text-gold whitespace-nowrap">
                      {item.price}
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          </motion.div>
        </div>
      </section>

      {/* Note */}
      <section className="bg-surface py-8">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 text-center">
          <p className="font-body text-sm text-zinc-500">
            * Prices inclusive of all taxes. Menu items subject to availability.
            <br />
            For dietary restrictions or allergies, please inform our staff.
          </p>
        </div>
      </section>

      {/* CTA */}
      <section className="bg-black py-16">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 text-center">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            viewport={{ once: true }}
          >
            <h2 className="font-heading text-3xl md:text-4xl text-white mb-6">
              Ready to Experience Our Menu?
            </h2>
            <a
              href="https://www.zomato.com/kolkata/corridor-bar-kitchen-chowringhee/book"
              target="_blank"
              rel="noopener noreferrer"
              data-testid="menu-reserve-btn"
              className="inline-block bg-gold text-black px-10 py-4 font-body text-sm tracking-[0.2em] uppercase hover:bg-white transition-all duration-300"
            >
              Reserve Your Table
            </a>
          </motion.div>
        </div>
      </section>

      <Footer />
    </main>
  );
};

export default MenuPage;
